#define HEADER_SIZE 10

typedef struct {
    char key[50];
    char value[100];
} HeaderEntry;

typedef struct {
    HeaderEntry entries[HEADER_SIZE];
    int count;
} HeaderDict;
// শীৰ্ষক অভিধানত এটা কীৰ সূচক বিচাৰি উলিওৱা কাৰ্য্য, যদি নাথাকে তেন্তে -1 ঘূৰাই আনেint find_header_index(const HeaderDict *header, const char *key) {
    for (int i = 0; i < header->count; i++) {
        if (strcmp(header->entries[i].key, key) == 0) {
            return i;
        }
    }
